import { test } from '../../../core/fixtures';
import { expect } from '@playwright/test';
import { ENV } from '../../../core/utils/envConfig';
import testData from './user-registration-account-deletion.data.json';

test.describe('User Registration and Account Deletion Suite', () => {
  test.describe.configure({ mode: 'serial' });

  /**
   * Journey 1 & 2 are combined as a single serial flow:
   * Signup → Fill Account Info → Create → Verify Login → Delete
   */
  test.describe('Happy Path: Full signup, account creation, and deletion flow', () => {
    test.describe.configure({ mode: 'serial' });

    const scenario = testData.scenarios.find((s) => s.id === 'TC-REG-001')!;
    const accountDetails = scenario.testData;

    test('Step 1: Navigate to home page and initiate signup', async ({
      page,
      homePage,
      loginPage,
    }) => {
      test.info().annotations.push({ type: 'feature', value: 'User Registration' });
      test.info().annotations.push({ type: 'severity', value: 'critical' });
      test.info().annotations.push({ type: 'tag', value: 'smoke' });
      test.info().annotations.push({ type: 'tag', value: 'regression' });
      test.info().annotations.push({ type: 'tag', value: 'signup' });

      // Navigate to home page
      await homePage.navigate();

      // Verify home page is loaded
      await expect(page.locator('body')).toBeVisible();
      expect(await homePage.isLoggedIn()).toBe(false);

      // Navigate to login/signup page
      await loginPage.navigate();

      // Verify New User Signup! heading is visible
      const signupHeading = page.locator('.signup-form h2');
      await expect(signupHeading).toBeVisible();
      await expect(signupHeading).toContainText(
        testData.constants.expectedMessages.signupHeading
      );

      // Fill in signup name and email using POM
      await loginPage.initiateSignup(
        accountDetails.signupName,
        accountDetails.signupEmail
      );

      // Verify ENTER ACCOUNT INFORMATION section is visible
      const accountInfoHeading = page.locator('[data-qa="account-info"] h2.title, .login-form h2.title, h2.title');
      await expect(accountInfoHeading.first()).toBeVisible();
    });

    test('Step 2: Fill account information and create account', async ({
      page,
      homePage,
    }) => {
      test.info().annotations.push({ type: 'feature', value: 'User Registration' });
      test.info().annotations.push({ type: 'severity', value: 'critical' });
      test.info().annotations.push({ type: 'tag', value: 'smoke' });
      test.info().annotations.push({ type: 'tag', value: 'regression' });
      test.info().annotations.push({ type: 'tag', value: 'account-creation' });

      // Select Title (Mr)
      await page.locator('#id_gender1').check();

      // Enter password
      await page.locator('[data-qa="password"]').fill(ENV.uiUserPassword);

      // Select date of birth
      await page.locator('[data-qa="days"]').selectOption(accountDetails.dobDay);
      await page.locator('[data-qa="months"]').selectOption(accountDetails.dobMonth);
      await page.locator('[data-qa="years"]').selectOption(accountDetails.dobYear);

      // Check newsletter and offers checkboxes
      await page.locator('#newsletter').check();
      await page.locator('#optin').check();

      // Verify checkboxes are checked
      await expect(page.locator('#newsletter')).toBeChecked();
      await expect(page.locator('#optin')).toBeChecked();

      // Fill address details
      await page.locator('[data-qa="first_name"]').fill(accountDetails.firstName);
      await page.locator('[data-qa="last_name"]').fill(accountDetails.lastName);
      await page.locator('[data-qa="company"]').fill(accountDetails.company);
      await page.locator('[data-qa="address"]').fill(accountDetails.address1);
      await page.locator('[data-qa="address2"]').fill(accountDetails.address2);
      await page.locator('[data-qa="country"]').selectOption(accountDetails.country);
      await page.locator('[data-qa="state"]').fill(accountDetails.state);
      await page.locator('[data-qa="city"]').fill(accountDetails.city);
      await page.locator('[data-qa="zipcode"]').fill(accountDetails.zipcode);
      await page.locator('[data-qa="mobile_number"]').fill(accountDetails.mobileNumber);

      // Click Create Account button
      await page.locator('[data-qa="create-account"]').click();

      // Verify ACCOUNT CREATED! message is visible
      const accountCreatedMsg = page.locator('h2.title b');
      await expect(accountCreatedMsg).toBeVisible();
      await expect(accountCreatedMsg).toContainText(
        testData.constants.expectedMessages.accountCreated
      );

      // Click Continue button after account creation
      await page.locator('[data-qa="continue-button"]').click();

      // Verify logged in as username is visible in navbar
      const loggedInUser = homePage.loggedInUser;
      await expect(loggedInUser).toBeVisible();
      await expect(loggedInUser).toContainText(accountDetails.signupName);
    });

    test('Step 3: Delete account and verify deletion', async ({ page }) => {
      test.info().annotations.push({ type: 'feature', value: 'User Registration' });
      test.info().annotations.push({ type: 'severity', value: 'critical' });
      test.info().annotations.push({ type: 'tag', value: 'smoke' });
      test.info().annotations.push({ type: 'tag', value: 'regression' });
      test.info().annotations.push({ type: 'tag', value: 'account-creation' });

      // Click Delete Account button
      await page.locator("a[href='/delete_account']").click();

      // Verify ACCOUNT DELETED! message is visible
      const accountDeletedMsg = page.locator('h2.title b');
      await expect(accountDeletedMsg).toBeVisible();
      await expect(accountDeletedMsg).toContainText(
        testData.constants.expectedMessages.accountDeleted
      );

      // Click Continue button after account deletion
      await page.locator('[data-qa="continue-button"]').click();

      // Capture final state after account deletion flow
      await page.screenshot({
        path: 'test-results/screenshots/account-deletion-complete.png',
        fullPage: true,
      });

      // Verify we are back on home page / not logged in
      await expect(page.locator('body')).toBeVisible();
      expect(await page.locator("a[href='/login']").isVisible()).toBe(true);
    });
  });

  /**
   * Journey 3: Negative — Signup with already registered email
   */
  test.describe('Negative: Signup with already registered email', () => {
    const scenario = testData.scenarios.find((s) => s.id === 'TC-REG-002')!;
    const existingUser = scenario.testData;

    test('Should display error when signing up with a duplicate email', async ({
      page,
      loginPage,
    }) => {
      test.info().annotations.push({ type: 'feature', value: 'User Registration' });
      test.info().annotations.push({ type: 'severity', value: 'high' });
      test.info().annotations.push({ type: 'tag', value: 'negative' });
      test.info().annotations.push({ type: 'tag', value: 'regression' });
      test.info().annotations.push({ type: 'tag', value: 'signup' });

      // Navigate to login/signup page
      await loginPage.navigate();

      // Verify New User Signup! heading is visible
      const signupHeading = page.locator('.signup-form h2');
      await expect(signupHeading).toBeVisible();
      await expect(signupHeading).toContainText(
        testData.constants.expectedMessages.signupHeading
      );

      // Enter name and already-registered email
      await loginPage.initiateSignup(
        existingUser.signupName,
        ENV.uiUserEmail
      );

      // Verify error message for duplicate email is shown
      const errorMsg = page.locator('p.text-danger');
      await expect(errorMsg).toBeVisible();
      await expect(errorMsg).toContainText(
        testData.constants.expectedMessages.duplicateEmailError
      );

      // Soft-assert the error text is exact
      expect.soft(await errorMsg.textContent()).toContain(
        testData.constants.expectedMessages.duplicateEmailError
      );

      // Capture error state screenshot
      await page.screenshot({
        path: 'test-results/screenshots/duplicate-email-error.png',
        fullPage: false,
      });
    });
  });
});
