import { test } from '../../../core/fixtures';
import { expect } from '@playwright/test';
import testData from './user-registration-flow.data.json';
import { ENV } from '../../../core/utils/envConfig';

// ─── Happy Path Suite ───────────────────────────────────────────────────────

test.describe('User Registration Flow – Happy Path', () => {
  test.describe.configure({ mode: 'serial' });

  test(
    'TC-REG-001: New user signup, account creation, and account deletion',
    async ({ page, homePage, loginPage }) => {
      test.info().annotations.push({ type: 'feature', value: 'Registration' });
      test.info().annotations.push({ type: 'severity', value: 'critical' });
      test.info().annotations.push({ type: 'tags', value: 'smoke,regression,auth' });

      const scenario = testData.scenarios.find((s) => s.id === 'TC-REG-001')!;
      const { newUser, accountDetails } = scenario.testData as {
        newUser: {
          name: string;
          email: string;
          day: string;
          month: string;
          year: string;
        };
        accountDetails: {
          firstName: string;
          lastName: string;
          company: string;
          address1: string;
          address2: string;
          country: string;
          state: string;
          city: string;
          zipcode: string;
          mobile: string;
        };
      };

      // ── Step 1: Navigate to home page ─────────────────────────────────────
      await homePage.navigate();
      await expect(page.locator('#header')).toBeVisible();

      // ── Step 2: Go to Login / Signup page ─────────────────────────────────
      await loginPage.navigate();
      await expect(page.locator('.signup-form h2')).toBeVisible();
      await expect(page.locator('.signup-form h2')).toHaveText(
        testData.constants.expectedMessages.newUserSignupHeading
      );

      // ── Step 3: Initiate signup ────────────────────────────────────────────
      await loginPage.initiateSignup(newUser.name, newUser.email);

      // ── Step 4: Verify account information form ────────────────────────────
      await expect(page.locator('[data-qa="account-info"] h2.title, .login-form h2.title')).toBeVisible();
      await expect(
        page.locator('[data-qa="account-info"] h2.title b, .login-form h2.title b')
      ).toHaveText(testData.constants.expectedMessages.enterAccountInfoHeading);

      // ── Step 5: Fill account details ──────────────────────────────────────
      await page.locator('input#id_gender1').check();
      await page.locator('[data-qa="password"]').fill(ENV.uiUserPassword);
      await page.locator('[data-qa="days"]').selectOption(newUser.day);
      await page.locator('[data-qa="months"]').selectOption(newUser.month);
      await page.locator('[data-qa="years"]').selectOption(newUser.year);
      await page.locator('input#newsletter').check();
      await page.locator('input#optin').check();

      // ── Step 6: Fill address information ──────────────────────────────────
      await page.locator('[data-qa="first_name"]').fill(accountDetails.firstName);
      await page.locator('[data-qa="last_name"]').fill(accountDetails.lastName);
      await page.locator('[data-qa="company"]').fill(accountDetails.company);
      await page.locator('[data-qa="address"]').fill(accountDetails.address1);
      await page.locator('[data-qa="address2"]').fill(accountDetails.address2);
      await page.locator('[data-qa="country"]').selectOption(accountDetails.country);
      await page.locator('[data-qa="state"]').fill(accountDetails.state);
      await page.locator('[data-qa="city"]').fill(accountDetails.city);
      await page.locator('[data-qa="zipcode"]').fill(accountDetails.zipcode);
      await page.locator('[data-qa="mobile_number"]').fill(accountDetails.mobile);

      // ── Step 7: Create account ─────────────────────────────────────────────
      await page.locator('[data-qa="create-account"]').click();

      // ── Step 8: Verify account created ────────────────────────────────────
      await expect(page.locator('h2.title b')).toBeVisible();
      await expect(page.locator('h2.title b')).toHaveText(
        testData.constants.expectedMessages.accountCreated
      );

      // ── Step 9: Continue to home ──────────────────────────────────────────
      await page.locator('[data-qa="continue-button"]').click();

      // ── Step 10: Verify logged in ─────────────────────────────────────────
      await expect(homePage.loggedInUser).toBeVisible();
      const loggedInUsername = await homePage.getLoggedInUsername();
      expect(loggedInUsername).toContain(newUser.name);

      // ── Step 11: Delete account ───────────────────────────────────────────
      await page.locator("a[href='/delete_account']").click();

      await expect(page.locator('h2.title b')).toBeVisible();
      await expect(page.locator('h2.title b')).toHaveText(
        testData.constants.expectedMessages.accountDeleted
      );

      // ── Step 12: Continue after deletion ─────────────────────────────────
      await page.locator('[data-qa="continue-button"]').click();

      // ── Step 13: Screenshot final state ──────────────────────────────────
      await page.screenshot({ path: 'test-results/TC-REG-001-final-state.png', fullPage: true });
    }
  );
});

// ─── Negative Case Suite ─────────────────────────────────────────────────────

test.describe('User Registration Flow – Negative Cases', () => {
  test(
    'TC-REG-002: Signup attempt with already registered email shows error',
    async ({ page, loginPage }) => {
      test.info().annotations.push({ type: 'feature', value: 'Registration' });
      test.info().annotations.push({ type: 'severity', value: 'high' });
      test.info().annotations.push({ type: 'tags', value: 'regression,auth,negative' });

      const scenario = testData.scenarios.find((s) => s.id === 'TC-REG-002')!;
      const { existingUser } = scenario.testData as {
        existingUser: { name: string; email: string };
      };

      // ── Step 1: Navigate to login/signup page ─────────────────────────────
      await loginPage.navigate();

      // ── Step 2: Verify signup form is visible ─────────────────────────────
      await expect(page.locator('.signup-form h2')).toBeVisible();
      await expect(page.locator('.signup-form h2')).toHaveText(
        testData.constants.expectedMessages.newUserSignupHeading
      );

      // ── Step 3: Attempt signup with existing email ────────────────────────
      await loginPage.initiateSignup(existingUser.name, existingUser.email);

      // ── Step 4: Verify duplicate email error is shown ─────────────────────
      await expect(page.locator('.signup-form p')).toBeVisible();
      await expect.soft(page.locator('.signup-form p')).toHaveText(
        testData.constants.expectedMessages.emailAlreadyExists
      );

      // Confirm user is NOT navigated away from the signup page
      expect.soft(page.url()).toContain(testData.constants.routes.loginUrl);

      // ── Step 5: Screenshot error state ────────────────────────────────────
      await page.screenshot({
        path: 'test-results/TC-REG-002-duplicate-email-error.png',
        fullPage: true,
      });
    }
  );
});
